[data-theme="my-theme"] {
  /* Background */
  --ply-bg-body: #___;
  --ply-bg-surface: #___;
  --ply-bg-surface-alt: #___;
  --ply-bg-muted: #___;

  /* Text */
  --ply-color-body: #___;
  --ply-color-headings: #___;
  --ply-color-secondary: #___;
  --ply-color-muted: #___;
  --ply-color-placeholder: #___;
  --ply-color-text-inverse: #___;

  /* Borders */
  --ply-border-color: #___;
  --ply-border-strong: #___;

  /* Interactive */
  --ply-color-accent: #___;
  --ply-color-focus: #___;
  --ply-color-link-hover: #___;

  /* Buttons */
  --ply-btn-default-bg: #___;
  --ply-btn-default-color: #___;
  --ply-btn-default-bg-hover: #___;
  --ply-btn-default-bg-active: #___;
  --ply-btn-secondary-bg: #___;
  --ply-btn-secondary-color: #___;
  --ply-btn-secondary-bg-hover: #___;
  --ply-btn-secondary-bg-active: #___;
  --ply-btn-border-radius: 2rem;

  /* Forms */
  --ply-color-input-bg: #___;
  --ply-color-input-border: #___;

  /* Navigation */
  --ply-nav-bg: #___;
  --ply-nav-color: #___;
  --ply-nav-border: #___;
  --ply-nav-hover: #___;

  /* Code */
  --ply-color-code-bg: #___;
  --ply-color-code-border: #___;

  /* Tables */
  --ply-color-table-border: #___;
  --ply-color-table-stripped: #___;

  /* Elevation */
  --ply-layer-0: #___;
  --ply-layer-1: #___;
  --ply-layer-2: #___;
  --ply-layer-3: #___;
  --ply-shadow-1: rgba(0, 0, 0, 0.08);
  --ply-shadow-2: rgba(0, 0, 0, 0.1);
  --ply-shadow-3: rgba(0, 0, 0, 0.12);

  /* Typography (optional) */
  --ply-font-body: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --ply-font-heading: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --ply-font-mono: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
}
